-- ng.cu_fctotal_v source

CREATE OR REPLACE VIEW ng.cu_fctotal_v
AS SELECT t.ac_code, t.ocode, t.compno, t.fc_code, t.uyear, 
    sum(t.inv_sum) AS inv_sum, sum(t.back_sum) AS back_sum, 
    sum(t.rec_sum) AS rec_sum, sum(t.disc_sum) AS disc_sum, 
    sum(t.bad_sum) AS bad_sum, sum(t.den_sum) AS den_sum, 
    sum(t.crn_sum) AS crn_sum, sum(t.def_sum) AS def_sum, 
    sum(t.crf_sum) AS crf_sum, sum(t.inv_init) AS inv_init, 
    sum(t.rec_init) AS rec_init, sum(t.baln_init) AS baln_init, 
    sum(t.balf_init) AS balf_init, sum(t.inv_ap00) AS inv_ap00, 
