    sum(t.back_ap02) AS back_ap02, sum(t.rec_ap02) AS rec_ap02, 
    sum(t.disc_ap02) AS disc_ap02, sum(t.bad_ap02) AS bad_ap02, 
    sum(t.den_ap02) AS den_ap02, sum(t.crn_ap02) AS crn_ap02, 
    sum(t.def_ap02) AS def_ap02, sum(t.crf_ap02) AS crf_ap02, 
    sum(t.inv_ap03) AS inv_ap03, sum(t.back_ap03) AS back_ap03, 
    sum(t.rec_ap03) AS rec_ap03, sum(t.disc_ap03) AS disc_ap03, 
    sum(t.bad_ap03) AS bad_ap03, sum(t.den_ap03) AS den_ap03, 
    sum(t.crn_ap03) AS crn_ap03, sum(t.def_ap03) AS def_ap03, 
    sum(t.crf_ap03) AS crf_ap03, sum(t.inv_ap04) AS inv_ap04, 
