    sum(t.rec_ap05) AS rec_ap05, sum(t.disc_ap05) AS disc_ap05, 
    sum(t.bad_ap05) AS bad_ap05, sum(t.den_ap05) AS den_ap05, 
    sum(t.crn_ap05) AS crn_ap05, sum(t.def_ap05) AS def_ap05, 
