   FROM (        (        (        (        (        (        (        (        (        (        (        (        (        (        (        (        (         SELECT t_in.ac_code, 
                                                                                                                                                    t_in.ocode, 
                                                                                                                                                    t_in.compno, 
                                                                                                                                                    t_in.fc_code, 
                                                                                                                                                    t_in.uyear, 
                                                                                                                                                    0.00 AS inv_sum, 
                                                                                                                                                    0.00 AS back_sum, 
                                                                                                                                                    0.00 AS rec_sum, 
                                                                                                                                                    0.00 AS disc_sum, 
                                                                                                                                                    0.00 AS bad_sum, 
                                                                                                                                                    0.00 AS den_sum, 
                                                                                                                                                    0.00 AS crn_sum, 
                                                                                                                                                    0.00 AS def_sum, 
                                                                                                                                                    0.00 AS crf_sum, 
                                                                                                                                                        CASE
                                                                                                                                                            WHEN sum(t_in.inv_fc) > 0::bigint::number THEN sum(t_in.inv_fc)
                                                                                                                                                            ELSE 0::bigint::number
                                                                                                                                                        END AS inv_init, 
                                                                                                                                                        CASE
                                                                                                                                                            WHEN sum(t_in.inv_fc) < 0::bigint::number THEN - sum(t_in.inv_fc)
                                                                                                                                                            ELSE 0::bigint::number
                                                                                                                                                        END AS rec_init, 
                                                                                                                                                    sum(t_in.inv_nc) AS baln_init, 
                                                                                                                                                    sum(t_in.inv_fc) AS balf_init, 
