                                                                                                                                                   FROM ( SELECT gl_assistant.ac_code, 
                                                                                                                                                            gl_assistant.ocode, 
                                                                                                                                                            gl_assistant.custom AS compno, 
                                                                                                                                                            gl_assistant.fc_code, 
                                                                                                                                                            gl_assistant.uyear, 
                                                                                                                                                            (gl_assistant.bf_bala OPERATOR(dolphin_catalog.+) gl_assistant.de_sum) OPERATOR(dolphin_catalog.-) gl_assistant.cr_sum AS inv_nc, 
                                                                                                                                                            (gl_assistant.bf_fc_bala OPERATOR(dolphin_catalog.+) gl_assistant.de_fc_sum) OPERATOR(dolphin_catalog.-) gl_assistant.cr_fc_sum AS inv_fc
                                                                                                                                                           FROM ng.gl_assistant
                                                                                                                                                          WHERE gl_assistant.custom IS NOT NULL AND NOT (gl_assistant.fc_code IN ( SELECT fg_data.data_str1
                                                                                                                                                                   FROM ng.fg_data
                                                                                                                                                                  WHERE fg_data.key1::text = 'fg_fcur'::text AND fg_data.key2::text = gl_assistant.ocode::text))) t_in, 
                                                                                                                                                    ng.gl_post
                                                                                                                                                  WHERE t_in.ocode::text = gl_post.ocode::text AND (gl_post.inited = 0::bigint OR gl_post.inited IS NULL) AND t_in.uyear::text = gl_post.uyear::text
                                                                                                                                                  GROUP BY t_in.ac_code, t_in.ocode, t_in.compno, t_in.fc_code, t_in.uyear
                                                                                                                                        UNION 
                                                                                                                                                 SELECT t_in.ac_code, 
                                                                                                                                                    t_in.ocode, 
                                                                                                                                                    t_in.compno, 
