                                                                                                                                                    0.00 AS balf_init, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SI'::text OR t_in.op_type::text = 'SL'::text THEN t_in.inv_fc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS inv_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SC'::text THEN t_in.inv_fc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS back_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SR'::text OR t_in.op_type::text = 'SX'::text OR t_in.op_type::text = 'SV'::text OR t_in.op_type::text = 'ST'::text THEN t_in.rec_fc
                                                                                                                                                            WHEN t_in.op_type::text = 'SA'::text THEN t_in.inv_fc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS rec_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SD'::text THEN t_in.disc_fc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS disc_ap00, 
                                                                                                                                                    sum(
                                                                                                                                                        CASE
                                                                                                                                                            WHEN t_in.op_type::text = 'SB'::text THEN t_in.inv_fc
                                                                                                                                                            WHEN t_in.op_type::text = 'SM'::text THEN - t_in.inv_fc
                                                                                                                                                            ELSE 0::number
                                                                                                                                                        END) AS bad_ap00, 
                                                                                                                                                    sum(t_in.de_tran) AS den_ap00, 
                                                                                                                                                    sum(t_in.cr_tran) AS crn_ap00, 
                                                                                                                                                    sum(t_in.de_tran_fc) AS def_ap00, 
